const topicParts = msg.topic.split("/");

const uniqueDeviceId = topicParts[1];
const temperature = Number(msg.payload);

if (!uniqueDeviceId || Number.isNaN(temperature)) {
    node.warn("Invalid HARDWARIO temperature message");
    return null;
}

const measuredAt = new Date().toISOString();

const measurementId =
    uniqueDeviceId + "-" + Date.now();

const measurementPayload = {
    measurementId,
    uniqueDeviceId,
    temperature,
    measuredAt
};

msg.headers = {
    "Content-Type": "application/json",
    "x-api-key": env.get("GATEWAY_API_KEY") || "abc123"
};

msg.payload = measurementPayload;

// save original payload for retry queue
msg.measurementPayload = measurementPayload;

return msg;

const statusCode = msg.statusCode;

if (statusCode >= 200 && statusCode < 300) {
    node.status({
        fill: "green",
        shape: "dot",
        text: "sent to backend"
    });

    return [msg, null];
}

node.status({
    fill: "red",
    shape: "ring",
    text: "backend failed, queueing"
});

return [null, msg];

const payload = msg.measurementPayload;

if (!payload || !payload.measurementId) {
    node.warn("Missing measurementPayload, cannot queue");
    return null;
}

const payloadJson = JSON.stringify(payload).replace(/'/g, "''");
const measurementId = payload.measurementId.replace(/'/g, "''");
const createdAt = new Date().toISOString();

msg.topic = `
INSERT OR IGNORE INTO retry_queue (
  measurementId,
  payload,
  createdAt,
  retryCount,
  lastRetryAt
)
VALUES (
  '${measurementId}',
  '${payloadJson}',
  '${createdAt}',
  0,
  NULL
);
`;

msg.payload = {};

return msg;

const topicParts = msg.topic.split("/");

const buttonDeviceId = topicParts[1];

const thermometerDeviceId =
    env.get("TEST_THERMOMETER_DEVICE_ID") || "test-thermometer-001";

const mockTemperature =
    Number(env.get("MOCK_TEMPERATURE") || 22.5);

msg.topic = `node/${thermometerDeviceId}/thermometer/0/temperature`;
msg.payload = mockTemperature;

msg.buttonDeviceId = buttonDeviceId;
msg.isMockMeasurement = true;

return msg;

msg.topic = `
SELECT * FROM retry_queue
ORDER BY createdAt ASC
LIMIT 20;
`;

return msg;

const row = msg.payload;

const payload = JSON.parse(row.payload);

msg.retryRowId = row.id;
msg.measurementPayload = payload;

msg.headers = {
    "Content-Type": "application/json",
    "x-api-key": env.get("GATEWAY_API_KEY") || "abc123"
};

msg.payload = payload;

return msg;

const statusCode = msg.statusCode;

if (statusCode >= 200 && statusCode < 300) {

    node.status({
        fill: "green",
        shape: "dot",
        text: "retry success"
    });

    msg.topic = `
    DELETE FROM retry_queue
    WHERE id = ${msg.retryRowId};
    `;

    msg.payload = {};

    return [msg, null];
}

node.status({
    fill: "red",
    shape: "ring",
    text: "retry failed"
});

return [null, msg];
